class Solution:
    def countPairs(self, n, edges, queries):
        deg = [0] * (n + 1)
        shared = {}
        for u, v in edges:
            deg[u] += 1
            deg[v] += 1
            if u > v:
                u, v = v, u
            shared[(u, v)] = shared.get((u, v), 0) + 1
        ans = []
        for q in queries:
            cnt = 0
            for a in range(1, n + 1):
                for b in range(a + 1, n + 1):
                    inc = deg[a] + deg[b] - shared.get((a, b), 0)
                    if inc > q:
                        cnt += 1
            ans.append(cnt)
        return ans

