class Solution:
    def countPairs(self, n, edges, queries):
        deg = [0] * (n + 1)
        shared = {}
        for u, v in edges:
            deg[u] += 1
            deg[v] += 1
            if u > v:
                u, v = v, u
            shared[(u, v)] = shared.get((u, v), 0) + 1
        sdeg = sorted(deg[1:])
        ans = []
        for q in queries:
            cnt = 0
            lo, hi = 0, n - 1
            while lo < hi:
                if sdeg[lo] + sdeg[hi] > q:
                    cnt += hi - lo
                    hi -= 1
                else:
                    lo += 1
            for (a, b), c in shared.items():
                da, db = deg[a], deg[b]
                if da + db > q and da + db - c <= q:
                    cnt -= 1
            ans.append(cnt)
        return ans

