var countPairs = function(n, edges, queries) {
    const deg = new Array(n + 1).fill(0);
    const shared = new Map();
    for (let [u, v] of edges) {
        deg[u]++; deg[v]++;
        if (u > v) { const t = u; u = v; v = t; }
        const key = u * 100000 + v;
        shared.set(key, (shared.get(key) || 0) + 1);
    }
    const sdeg = deg.slice(1).sort((a, b) => a - b);
    const ans = [];
    for (const q of queries) {
        let cnt = 0;
        let lo = 0, hi = n - 1;
        while (lo < hi) {
            if (sdeg[lo] + sdeg[hi] > q) { cnt += hi - lo; hi--; }
            else lo++;
        }
        for (const [key, c] of shared) {
            const a = Math.floor(key / 100000), b = key % 100000;
            const sum = deg[a] + deg[b];
            if (sum > q && sum - c <= q) cnt--;
        }
        ans.push(cnt);
    }
    return ans;
};
